/// clear BSS segment
fn clear_bss() {
    extern "C" {
        fn sbss();
        fn ebss();
    }
    unsafe {
        ptr::write_bytes(sbss as *mut c_void, 0, ebss as usize - sbss as usize);
    }
}

#[no_mangle]
pub fn fake_main(hart_id: usize) {
    #[cfg(target_arch = "riscv64")]
    unsafe {
        asm!("add sp, sp, {}", in(reg) KERNEL_BASE);
        asm!("la t0, rust_main");
        asm!("add t0, t0, {}", in(reg) KERNEL_BASE);
        asm!("mv a0, {}", in(reg) hart_id);
        asm!("jalr zero, 0(t0)");
    }
    #[cfg(target_arch = "loongarch64")]
    unsafe {
        asm!("la.global $t0, rust_main");
        asm!("move $a0, {}", in(reg) hart_id);
        asm!("jirl $zero, $t0, 0");
    }
}

