use std::fs::{metadata, read_dir, File};
use std::io::{Result, Write};

fn main() {
    let target_path = target_path();
    println!("cargo:rerun-if-changed=../user/src/");
    println!("cargo:rerun-if-changed=src/linker.ld");
    println!("cargo:rerun-if-changed=src/linker_loongarch64.ld");
    println!("cargo:rerun-if-changed={}", target_path);
    insert_app_data(&target_path).unwrap();
}

fn target_path() -> String {
    if let Ok(path) = std::env::var("USER_TARGET_PATH") {
        return path;
    }
    let target = std::env::var("TARGET").unwrap();
    let profile = std::env::var("PROFILE").unwrap_or_else(|_| "release".to_string());
    format!("../user/target/{target}/{profile}/")
}

fn insert_app_data(target_path: &str) -> Result<()> {
    let mut f = File::create("src/link_app.S").unwrap();
    let mut apps: Vec<_> = read_dir("../user/src/bin")
        .unwrap()
        .into_iter()
        .map(|dir_entry| {
            let mut name_with_ext = dir_entry.unwrap().file_name().into_string().unwrap();
            name_with_ext.drain(name_with_ext.find('.').unwrap()..name_with_ext.len());
            name_with_ext
        })
        .collect();
    apps.sort();

    writeln!(
        f,
        r#"
    .align 3
    .section .data
    .global _num_app
_num_app:
    .quad {}"#,
        apps.len()
    )?;

    for i in 0..apps.len() {
        writeln!(f, r#"    .quad app_{}_start"#, i)?;
    }
    writeln!(f, r#"    .quad app_{}_end"#, apps.len() - 1)?;

    writeln!(
        f,
        r#"
    .global _app_names
_app_names:"#
    )?;
    for app in apps.iter() {
        writeln!(f, r#"    .string "{}""#, app)?;
    }

    for (idx, app) in apps.iter().enumerate() {
        let app_path = format!("{}{}", target_path, app);
        println!("cargo:rerun-if-changed={}", app_path);
        println!("app_{}: {}", idx, app);
        let app_meta = metadata(&app_path)?;
        let app_len = app_meta.len();
        let app_mtime = app_meta
            .modified()
            .ok()
            .and_then(|time| time.duration_since(std::time::UNIX_EPOCH).ok())
            .map(|duration| duration.as_nanos())
            .unwrap_or(0);
        writeln!(
            f,
            r#"
    .section .data
    .global app_{0}_start
    .global app_{0}_end
    /* app stamp: len={3}, mtime={4} */
    .align 3
app_{0}_start:
    .incbin "{2}{1}"
app_{0}_end:"#,
            idx, app, target_path, app_len, app_mtime
        )?;
    }
    Ok(())
}

