fn ltp_selected_script_is_current(fd: usize, expected: &[u8]) -> bool {
    let mut offset = 0usize;
    let mut buf = [0u8; 256];

    loop {
        let n = sys_read(fd, &mut buf);
        if n < 0 {
            return false;
        }
        if n == 0 {
            return offset == expected.len();
        }

        let n = n as usize;
        if offset + n > expected.len() {
            return false;
        }
        if &buf[..n] != &expected[offset..offset + n] {
            return false;
        }
        offset += n;
    }
}

pub fn install_ltp_selected_scripts() {
    const O_WRONLY: u32 = 0x1;
    const O_CREAT: u32 = 0x40;
    const AT_FDCWD: i32 = -100;

    for asset in LTP_SELECTED_SCRIPT_ASSETS {
        let path = asset.path;
        let mut path_buf = alloc::string::String::from(path);
        path_buf.push('\0');
        let existing_fd = sys_open(path_buf.as_ptr(), OpenFlags::RDONLY.bits);
        if existing_fd >= 0 {
            if ltp_selected_script_is_current(existing_fd as usize, asset.content.as_bytes()) {
                let _ = sys_close(existing_fd as usize);
                continue;
            }
            let _ = sys_close(existing_fd as usize);
            let rc = sys_unlinkat(AT_FDCWD, path_buf.as_ptr(), 0);
            if rc < 0 {
                continue;
            }
        }

        let fd = sys_openat_mode(path_buf.as_ptr(), O_WRONLY | O_CREAT, 0o644);
        if fd < 0 {
            continue;
        }

        let fd = fd as usize;
        let data = asset.content.as_bytes();
        let mut written = 0usize;
        while written < data.len() {
            let n = sys_write(fd, &data[written..]);
            if n <= 0 {
                break;
            }
            written += n as usize;
        }
        let _ = sys_close(fd);
    }
}

pub fn wait(exit_code: &mut i32) -> isize {
    loop {
        match sys_waitpid(-1, exit_code as *mut _) {
            // 新内核语义: -10 = ECHILD，表示没有任何可等待子进程
            -10 => return -1,
            // 其他负 errno 都是实际错误，不能当作“继续等待”。
            errno if errno < 0 => return errno,
            exit_pid => return exit_pid,
        }
    }
}

